const input = $input.first().json;
const isTelegram = input.message !== undefined;

let result;
if (isTelegram) {
  result = {
    source: 'telegram',
    userId: input.message.from.id.toString(),
    chatId: input.message.chat.id,
    message: input.message.text || '',
    name: input.message.from.first_name
  };
} else {
  result = {
    source: 'whatsapp',
    userId: input.From,
    chatId: input.From,
    message: input.Body || '',
    name: input.ProfileName || 'Cliente'
  };
}

return [{json: result}];

const { source, chatId, name } = $input.first().json;
const aiResponse = $input.first().json.content || 'Hola! Soy el asistente de Kyros.';

let output;
if (source === 'telegram') {
  output = { chat_id: chatId, text: aiResponse };
} else {
  output = { To: chatId, Body: aiResponse };
}

return [{ json: { output, source, chatId, name } }];
